public List<Order> getActiveOrders(Long userId) {
    List<Order> all = orderRepo.findByUserId(userId);
    return all.stream().filter(o -> o.getStatus() == ACTIVE)
        .sorted(Comparator.comparing(Order::getCreatedAt))
        .collect(Collectors.toList());
}
public List<Order> getCancelledOrders(Long userId) {
    List<Order> all = orderRepo.findByUserId(userId);
    return all.stream().filter(o -> o.getStatus() == CANCELLED)
        .sorted(Comparator.comparing(Order::getCreatedAt))
        .collect(Collectors.toList());
}

